mapper.select:
SELECT
    NVL(STOCK_RESERVES, 0)
FROM STOCKS_HELD
WHERE ACCOUNT_NO = #{accountNo}
  AND STOCK_CODE = #{stockCode}

mapper.update:
UPDATE ACCOUNT_BALANCE
SET AVAILABLE_CASH = NVL(AVAILABLE_CASH, 0) - #{orderAmount}
WHERE ACCOUNT_NO = #{accountNo}
  AND NVL(AVAILABLE_CASH, 0) >= #{orderAmount}

UPDATE ACCOUNT_BALANCE
SET AVAILABLE_CASH = NVL(AVAILABLE_CASH, 0) + #{orderAmount}
WHERE ACCOUNT_NO = #{accountNo}

UPDATE STOCKS_HELD
SET STOCK_RESERVES = STOCK_RESERVES - #{quantity}
WHERE ACCOUNT_NO = #{accountNo}
  AND STOCK_CODE = #{stockCode}
  AND STOCK_RESERVES >= #{quantity}
